/**
 * Returns monthly spend totals, WO volume, building breakdown, and category breakdown computed from work order history.
 * @summary Get financial spend report
 */
export const getGetSpendReportUrl = (params?: GetSpendReportParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/reports/spend?${stringifiedParams}`
    : `/api/reports/spend`;
};

